import React from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Login from "./Login";
import Signup from "./Signup";
import Admingifts from "./Admingifts";
import EditAdmin from "./EditGifts";
import AddTheme from "./AdminTheme";
import EditTheme from "./EditTheme";
import Orders from "./orders";
export default function App(){
    return(<div className="App">
    <BrowserRouter>
    <Routes>
        <Route path="/" element={<Signup/>}></Route>
        <Route path="/login" element={<Login/>}></Route>      
        <Route path = "/addGift" element={<Admingifts/>}> </Route> 
        <Route path = "/editGift" element={<EditAdmin/>}> </Route> 
        <Route path = "/addTheme" element={<AddTheme/>}> </Route> 
        <Route path = "/editTheme" element={<EditTheme/>}> </Route> 
        <Route path = "/orders" element={<Orders/>}> </Route>
    </Routes>
    </BrowserRouter>
    </div>)
}
